{
  "name": "Fuel Assistance (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross annual household income cannot exceed 60% of Massachusetts' estimated State Median Income for FY 2026. Limits by household size: 1: $51,777; 2: $67,709; 3: $83,641; 4: $99,573; 5: $115,504; 6: $131,436; 7: $127,720-$134,423 (slight source variation); 8: $134,423-$137,410; 9: $137,410; 10: $140,397. Income considered for all members 18+; contact local agency for full criteria including housing subsidies.[1][3][4]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Reside in Massachusetts", "Homeowners and renters eligible, including those with heat included in rent", "Must apply each year", "Additional factors like housing subsidies affect eligibility; contact local agency for details"][1][4]
  },
  "benefits": {
    "type": "financial",
    "value": "Fixed benefit payments made directly to heating vendor for primary energy needs (oil, electricity, natural gas, propane, kerosene, wood, coal) from November 1 to April 30. Exact amounts vary by income, household size, housing subsidies, and fuel type; see local agency or FY 2026 LIHEAP Income Eligibility and Benefit Chart for specifics. Renters with heat included may receive monthly income subsidy if paying over 30% of income toward rent.[1][2][3]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: https://www.toapply.org/MassHEAP (opens October 1 for heating season November 1-April 30)", "Phone: Call local agency (find via https://www.mass.gov/how-to/apply-for-home-heating-and-energy-assistance, Cold Relief Heatline (800) 632-8175, or region-specific like Boston/Brookline/Newton: 617.357.6012, Malden area: 781.322.6284)", "Mail: To local agency", "In-person: At local LIHEAP agency (e.g., Valley Opportunity Council in Hampden County: Chicopee 413-552-1548, Holyoke locations; ABCD sites for Boston area)"],
    "processing_time": "Not specified; applications processed for heating season November 1-April 30, 2026 deadline April 30.",
    "waitlist": null,
    "forms": ["Recertification application (mailed to prior recipients)", "Printable forms from local providers like ABCD"],
    "documents": ["Photo ID for head of household (e.g., driver's license)", "List of all household members", "Heating bills (company name, account number)", "Housing info (lease, mortgage statement)", "Proof of income for 30 days prior to application (wages, pension)"] [1][3][4]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to residents",
    "regional_variations": "Administered by local agencies with varying offices, phone numbers, and potentially benefit levels or processing; e.g., Valley Opportunity Council (Hampden County), ABCD (Boston area), Self Help Inc. (other areas). Use agency lookup tool for specifics.[1][2][3]",
    "offices_or_providers": ["Local fuel assistance agencies; find via Mass.gov portal, Cold Relief Heatline (800) 632-8175, or FY 2026 Cold Relief Brochure"]
  },
  "official_source": "https://www.mass.gov/how-to/apply-for-home-heating-and-energy-assistance",
  "gotchas": ["Must apply every year even if previously approved", "Income based on gross annual for all adults 18+; not just public assistance recipients", "Heat-in-rent households need to pay >30% income toward rent for subsidy eligibility", "Online app opens October 1; season ends April 30", "Housing subsidies and fuel type affect benefit amount—check with local agency", "Over-income households may qualify for Mass Save Moderate Income program instead (call 1-866-527-7283)"][1][2][6],
  "data_shape_notes": "Income eligibility at exactly 60% SMI with full household size table; benefits are fixed amounts varying by household size, income, fuel type, housing status, and local agency; administered via multiple regional providers statewide"
}

{
  "name": "Family Caregiver Support Program (includes Respite)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits specified; program is free for eligible caregivers.[1][8]",
    "asset_limits": "No asset limits or countable/exempt asset rules mentioned.[1][8]",
    "other_requirements": [
      "Caregiver: Adult family member or non-paid caregiver, age 18+ (or grandparent/relative age 55+ for children under 18 or adults 18-59 with disability).[1][8]",
      "Care recipient: Age 60+ or any age with Alzheimer's/related dementia; or for grandparents/relatives: child under 18 or adult 18-59 with disability.[1][8]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Respite care (temporary relief for caregivers), counseling, training, support groups, and supplemental services; specific respite details (e.g., hours, dollar amounts) not quantified in sources and vary by local provider.[1][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Contact local Aging Service Access Points (ASAPs) via phone: (800) 243-4636 or search at https://contactus.800ageinfo.com/FindAgency.aspx[5]",
      "In-person or phone through regional ASAP offices[5]"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not mentioned; may vary by region or enrollment caps in related waivers (e.g., 120-20,000 slots in waivers).[5]",
    "forms": ["Request clinical eligibility assessment; no specific form name/number listed.[5]"],
    "documents": ["Not detailed; prepare proof of caregiver relationship, care recipient age/diagnosis (e.g., Alzheimer's documentation).[1][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; delivered through 26 regional Aging Service Access Points (ASAPs).[5]",
    "regional_variations": "Administered locally by ASAPs with potential differences in providers, services, and wait times; enrollment limits in some waivers.[5]",
    "offices_or_providers": ["Local ASAPs; find via (800) 243-4636 or https://contactus.800ageinfo.com/FindAgency.aspx[5]"]
  },
  "official_source": "https://www.mass.gov/info-details/family-caregiver-support-program[8]",
  "gotchas": [
    "Not exclusively for elderly (includes dementia any age, relatives caring for children/disabled adults); respite often via waivers with caps.[1][5][8]",
    "Free but may have regional availability limits; not paid caregiver compensation (family unpaid).[1][8]",
    "Confused with MassHealth PCA/AFC (those require MassHealth enrollment, co-residency, ADL needs, may pay family).[2][3][4]",
    "Legal guardians often ineligible for respite in waivers.[5]"
  ],
  "data_shape_notes": "No income/asset test; caregiver-focused with tiered recipient categories; regional ASAP delivery with waiver enrollment caps; respite embedded in broader supports, not standalone quantified hours/dollars."
}

{
  "name": "Massachusetts Senior Legal Helpline",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits specified for the helpline itself; eligibility for free attorney representation through referrals may depend on income guidelines of partnered civil legal services programs (e.g., below 125% of federal poverty level in some cases, but not required for helpline services)",
    "asset_limits": "No asset limits mentioned",
    "other_requirements": ["Massachusetts resident", "Civil legal issues only (e.g., excludes criminal matters, medical malpractice, workers’ compensation, personal injury unless specified)"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal information, advice, and referrals on civil law topics including Social Security/SSI, veterans benefits, MassHealth, Medicare, consumer issues, public benefits, unemployment, foreclosures, guardianship, power of attorney, wills/advance directives, bankruptcy, evictions, landlord/tenant, utilities, family law, nursing home issues; possible referral to free attorney (most callers ineligible), reduced-fee attorneys on sliding scale, private bar referrals, or written materials via text/email/mail",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-342-5297 (Mon-Fri 9AM-12PM)", "Download brochure for more info: https://www.mass.gov/doc/senior-legal-help-line/download"],
    "processing_time": "Immediate phone consultation during hours; referrals or attorney eligibility determined during call",
    "waitlist": null,
    "forms": ["No specific form for helpline; application for free attorney completed over phone if eligible via partnered programs"],
    "documents": ["No documents required for initial helpline call; may need income/financial details if applying for free attorney referral"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Massachusetts residents 60+ statewide",
    "regional_variations": "Operated by Volunteer Lawyers Project of Boston, with some listings noting service in specific areas (e.g., Northeast MA towns like Amesbury, Lowell), but described as statewide with no restrictions",
    "offices_or_providers": ["Volunteer Lawyers Project of Boston"]
  },
  "official_source": "https://www.mass.gov/doc/senior-legal-help-line/download",
  "gotchas": ["Most callers not eligible for free attorney—primarily information/referral service; limited hours (Mon-Fri 9AM-12PM); civil law only, no criminal cases; separate from Attorney General's Elder Hotline (888-243-5337) which focuses on consumer/abuse issues; one outdated source lists different phone (1-866-778-0939)—use 800-342-5297"],
  "data_shape_notes": "no income test for core helpline access; free info/referrals to all qualifying seniors regardless of finances; attorney services via referral with potential means test; statewide but run by single Boston-based provider"
}
